// Merge all — full translations for every supported language
const translations: Record<string, Record<string, string>> = {
  en, tr, es, ru, zh, fr, th, ar, de, ja, ko, pt, it, nl, pl, vi, id, hi, bn, uk, cs, el, hu, ro, sv, da, fi, no, he, fa, ms, ta, te, mr, gu, kn, ml, pa, si, my, km, lo, ne, ur, sw, am, ha, yo, ig, zu, af, sq, hy, az, be, bs, bg, hr, ka, mk, sr, sk, sl, et, lv, lt, mt, cy, ga, is, lb,
};

for (const lang of LANGUAGES) {
  resources[lang] = { translation: translations[lang] || en };
}

i18n
  .use(LanguageDetector)
  .use(initReactI18next)
  .init({
    resources,
    fallbackLng: "en",
    supportedLngs: LANGUAGES,
    interpolation: { escapeValue: false },
    detection: {
      order: ["querystring", "localStorage", "navigator", "htmlTag"],
      lookupQuerystring: "lang",
      lookupLocalStorage: "i18nextLng",
      caches: ["localStorage"],
    },
  });

// Update html lang and dir (RTL for Arabic) when language changes
i18n.on("languageChanged", (lng) => {
  const html = document.documentElement;
  const code = lng.split("-")[0];
  html.lang = lng;
  html.dir = code === "ar" ? "rtl" : "ltr";
});

export default i18n;
export { LANGUAGES };
